function solve(m, n, waitCost) {
    const dp = new Array(m).fill().map(() => new Array(n).fill(Infinity));
    dp[0][0] = (0 + 1) * (0 + 1); // initial cost to enter (0,0)

    const directions = [[1, 0], [0, 1]]; // down and right

    const heap = new MinPriorityQueue({ priority: (node) => node.cost });
    heap.enqueue({ i: 0, j: 0, cost: dp[0][0], time: 1 });

    while (!heap.isEmpty()) {
        const { i, j, cost, time } = heap.dequeue().element;

        if (i === m - 1 && j === n - 1) {
            return cost;
        }

        if (time % 2 === 1) { // odd time: move
            for (const [di, dj] of directions) {
                const ni = i + di;
                const nj = j + dj;
                if (ni < m && nj < n) {
                    const newCost = cost + (ni + 1) * (nj + 1);
                    if (newCost < dp[ni][nj]) {
                        dp[ni][nj] = newCost;
                        heap.enqueue({ i: ni, j: nj, cost: newCost, time: time + 1 });
                    }
                }
            }
        } else { // even time: wait
            const newCost = cost + waitCost[i][j];
            if (newCost < dp[i][j]) {
                dp[i][j] = newCost;
                heap.enqueue({ i, j, cost: newCost, time: time + 1 });
            }
        }
    }

    return dp[m - 1][n - 1];
}

class MinPriorityQueue {
    constructor({ priority }) {
        this.heap = [];
        this.priority = priority;
    }

    enqueue(element) {
        this.heap.push(element);
        this.bubbleUp(this.heap.length - 1);
    }

    dequeue() {
        const min = this.heap[0];
        const end = this.heap.pop();
        if (this.heap.length > 0) {
            this.heap[0] = end;
            this.bubbleDown(0);
        }
        return { element: min };
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    bubbleUp(index) {
        const element = this.heap[index];
        const priority = this.priority(element);

        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            const parent = this.heap[parentIndex];
            if (priority >= this.priority(parent)) break;
            this.heap[index] = parent;
            index = parentIndex;
        }
        this.heap[index] = element;
    }

    bubbleDown(index) {
        const element = this.heap[index];
        const priority = this.priority(element);
        const length = this.heap.length;

        while (true) {
            let leftChildIndex = 2 * index + 1;
            let rightChildIndex = 2 * index + 2;
            let swapIndex = null;

            if (leftChildIndex < length) {
                const leftChild = this.heap[leftChildIndex];
                if (this.priority(leftChild) < priority) {
                    swapIndex = leftChildIndex;
                }
            }

            if (rightChildIndex < length) {
                const rightChild = this.heap[rightChildIndex];
                if (
                    (swapIndex === null && this.priority(rightChild) < priority) ||
                    (swapIndex !== null && this.priority(rightChild) < this.priority(this.heap[swapIndex]))
                ) {
                    swapIndex = rightChildIndex;
                }
            }

            if (swapIndex === null) break;
            this.heap[index] = this.heap[swapIndex];
            index = swapIndex;
        }
        this.heap[index] = element;
    }
}

