package main

import (
	"container/heap"
)

type Node struct {
	i    int64
	j    int64
	cost int64
	time int64
}

type PriorityQueue []*Node

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].cost < pq[j].cost
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	node := x.(*Node)
	*pq = append(*pq, node)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	node := old[n-1]
	*pq = old[0 : n-1]
	return node
}

func solve(m int64, n int64, waitCost [][]int64) int64 {
	dp := make([][]int64, m)
	for i := range dp {
		dp[i] = make([]int64, n)
		for j := range dp[i] {
			dp[i][j] = 1 << 62
		}
	}
	dp[0][0] = (0 + 1) * (0 + 1)

	directions := [][]int64{{1, 0}, {0, 1}}

	pq := make(PriorityQueue, 0)
	heap.Init(&pq)
	heap.Push(&pq, &Node{i: 0, j: 0, cost: dp[0][0], time: 1})

	for pq.Len() > 0 {
		node := heap.Pop(&pq).(*Node)
		i, j, cost, time := node.i, node.j, node.cost, node.time

		if i == m-1 && j == n-1 {
			return cost
		}

		if time%2 == 1 {
			for _, dir := range directions {
				ni := i + dir[0]
